const xml = items[0].json.data;
const itemMatches = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
while ((match = itemRegex.exec(xml)) !== null && itemMatches.length < 3) {
  itemMatches.push(match[1]);
}

function getTagContent(xmlStr, tagName) {
  const regex = new RegExp('<' + tagName + '(?:\\s+[^>]*)*>([\s\S]*?)<\/' + tagName + '>', 'i');
  const m = xmlStr.match(regex);
  if (m) {
    let content = m[1];
    if (content.indexOf('<![CDATA[') !== -1) {
      content = content.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1');
    }
    return content.trim();
  }
  return '';
}

function getAttributeValue(xmlStr, tagName, attrName) {
  const regex = new RegExp('<' + tagName + '\\s+[^>]*?' + attrName + '=[\"\']([^\"\']+)[\"\']', 'i');
  const m = xmlStr.match(regex);
  return m ? m[1] : '';
}

return itemMatches.map(itemXml => {
  const title = getTagContent(itemXml, 'title');
  const link = getTagContent(itemXml, 'link');
  const description = getTagContent(itemXml, 'description');
  let content = getTagContent(itemXml, 'content:encoded');
  if (!content) {
    content = getTagContent(itemXml, 'description');
  }
  const pubDate = getTagContent(itemXml, 'pubDate');
  const image_url = getAttributeValue(itemXml, 'enclosure', 'url');

  return {
    json: {
      title,
      link,
      description,
      content,
      pubDate,
      image_url
    }
  };
});

